/**
 * OpenTelemetry initialization (README §2.6 Distributed Tracing).
 * MUST be required BEFORE any instrumented module is imported — the API is
 * started with `node --require ./dist/tracing.js dist/main.js` (README §2.9 Docker).
 *
 * Auto-instruments HTTP, Express, ioredis, BullMQ, and Prisma. Spans are exported
 * via OTLP/gRPC to the collector (Jaeger) when OTEL_EXPORTER_OTLP_ENDPOINT is set.
 */
import { NodeSDK } from '@opentelemetry/sdk-node';
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-grpc';

const endpoint = process.env.OTEL_EXPORTER_OTLP_ENDPOINT;

const sdk = new NodeSDK({
  serviceName: 'smartcart-api',
  // No endpoint configured ⇒ no exporter ⇒ tracing is a no-op (safe for local dev).
  traceExporter: endpoint ? new OTLPTraceExporter({ url: endpoint }) : undefined,
  instrumentations: [
    getNodeAutoInstrumentations({
      // fs spans are noisy and low-value; disable per OTel guidance.
      '@opentelemetry/instrumentation-fs': { enabled: false },
    }),
  ],
});

try {
  sdk.start();
} catch (err) {
  // Never let tracing init crash the process.
  // eslint-disable-next-line no-console
  console.error('[tracing] failed to start OpenTelemetry SDK', err);
}

process.on('SIGTERM', () => {
  void sdk.shutdown().finally(() => process.exit(0));
});
